     1→#!/usr/bin/env bun
     2→/**
     3→ * PAI Installation Wizard - Cross-Platform v2.5
     4→ *
     5→ * Interactive setup that walks you through personalizing your PAI:
     6→ * - Sets your name and timezone
     7→ * - Names your AI assistant
     8→ * - Configures voice settings
     9→ * - Fixes permissions and starts services
    10→ *
    11→ * Platform Support:
    12→ * - Windows: PowerShell + Windows commands
    13→ * - macOS: zsh + Unix commands
    14→ * - Linux: bash/zsh + Unix commands
    15→ *
    16→ * Usage:
    17→ *   bun run INSTALL.ts    # Run the interactive wizard
    18→ */
    19→
    20→import { existsSync, mkdirSync, readFileSync, writeFileSync, readdirSync } from 'fs';
    21→import { join, sep } from 'path';
    22→import { homedir, userInfo, platform } from 'os';
    23→import { execSync, spawn } from 'child_process';
    24→import * as readline from 'readline';
    25→
    26→// ============================================================================
    27→// PLATFORM DETECTION
    28→// ============================================================================
    29→
    30→const PLATFORM = process.platform;
    31→const IS_WINDOWS = PLATFORM === 'win32';
    32→const IS_MAC = PLATFORM === 'darwin';
    33→const IS_LINUX = PLATFORM === 'linux';
    34→
    35→// Platform-specific paths
    36→const HOME = IS_WINDOWS
    37→  ? process.env.USERPROFILE || homedir()
    38→  : process.env.HOME || homedir();
    39→
    40→const CLAUDE_DIR = join(HOME, '.claude');
    41→const VOICE_SERVER_DIR = join(CLAUDE_DIR, 'VoiceServer');
    42→const VOICE_SERVER_PORT = 8888;
    43→
    44→// ANSI colors (work on all platforms with modern terminals)
    45→const c = {
    46→  reset: '\x1b[0m',
    47→  bold: '\x1b[1m',
    48→  blue: '\x1b[38;2;59;130;246m',
    49→  green: '\x1b[38;2;34;197;94m',
    50→  yellow: '\x1b[38;2;234;179;8m',
    51→  red: '\x1b[38;2;239;68;68m',
    52→  cyan: '\x1b[38;2;6;182;212m',
    53→  gray: '\x1b[38;2;100;116;139m',
    54→};
    55→
    56→// Default voice IDs - ElevenLabs pre-made voices
    57→const DEFAULT_VOICES = {
    58→  male: 'pNInz6obpgDQGcFmaJgB',      // Adam (male)
    59→  female: '21m00Tcm4TlvDq8ikWAM',    // Rachel (female)
    60→  neutral: 'ErXwobaYiN019PkySvjV',   // Antoni (versatile male)
    61→};
    62→
    63→interface InstallConfig {
    64→  PRINCIPAL_NAME: string;
    65→  TIMEZONE?: string;
    66→  AI_NAME?: string;
    67→  CATCHPHRASE?: string;
    68→  VOICE_TYPE?: 'male' | 'female' | 'neutral';
    69→  ELEVENLABS_KEY?: string;
    70→  CUSTOM_VOICE_ID?: string;
    71→  PROJECTS_DIR?: string;
    72→}
    73→
    74→// ============================================================================
    75→// UTILITY FUNCTIONS
    76→// ============================================================================
    77→
    78→function print(msg: string) { console.log(msg); }
    79→function printSuccess(msg: string) { print(`  ${c.green}✓${c.reset} ${msg}`); }
    80→function printWarning(msg: string) { print(`  ${c.yellow}!${c.reset} ${msg}`); }
    81→function printError(msg: string) { print(`  ${c.red}✗${c.reset} ${msg}`); }
    82→function printInfo(msg: string) { print(`  ${c.gray}→${c.reset} ${msg}`); }
    83→
    84→function createReadline(): readline.Interface {
    85→  return readline.createInterface({
    86→    input: process.stdin,
    87→    output: process.stdout,
    88→  });
    89→}
    90→
    91→async function prompt(question: string, defaultValue?: string): Promise<string> {
    92→  const displayDefault = defaultValue ? ` ${c.gray}[${defaultValue}]${c.reset}` : '';
    93→  const rl = createReadline();
    94→
    95→  return new Promise((resolve) => {
    96→    rl.question(`  ${question}${displayDefault}: `, (answer) => {
    97→      rl.close();
    98→      resolve(answer.trim() || defaultValue || '');
    99→    });
   100→  });
   101→}
   102→
   103→async function promptChoice(question: string, choices: string[], defaultIdx = 0): Promise<number> {
   104→  print(`  ${question}`);
   105→  choices.forEach((choice, i) => {
   106→    const marker = i === defaultIdx ? `${c.cyan}→${c.reset}` : ' ';
   107→    print(`    ${marker} ${i + 1}. ${choice}`);
   108→  });
   109→
   110→  const rl = createReadline();
   111→  return new Promise((resolve) => {
   112→    rl.question(`  ${c.gray}Enter 1-${choices.length} [${defaultIdx + 1}]:${c.reset} `, (answer) => {
   113→      rl.close();
   114→      const num = parseInt(answer.trim()) || (defaultIdx + 1);
   115→      resolve(Math.max(0, Math.min(choices.length - 1, num - 1)));
   116→    });
   117→  });
   118→}
