   120→// ============================================================================
   121→// CROSS-PLATFORM PERMISSIONS
   122→// ============================================================================
   123→
   124→function fixPermissions(targetDir: string): void {
   125→  print('');
   126→  print(`${c.bold}Fixing permissions${c.reset}`);
   127→  print(`${c.gray}─────────────────────────────────────────────────${c.reset}`);
   128→
   129→  try {
   130→    if (IS_WINDOWS) {
   131→      // Windows: Use icacls if needed, or skip (default permissions usually OK)
   132→      printInfo('Platform: Windows (using default permissions)');
   133→
   134→      try {
   135→        const username = userInfo().username;
   136→        execSync(`icacls "${targetDir}" /grant "${username}:(OI)(CI)F" /T`, {
   137→          stdio: 'pipe',
   138→          shell: true
   139→        });
   140→        printSuccess('Set Windows permissions');
   141→      } catch (err) {
   142→        printWarning('icacls failed (may need admin privileges)');
   143→        printInfo('Default permissions should work for most operations');
   144→      }
   145→    } else {
   146→      // Unix: chmod and chown
   147→      const info = userInfo();
   148→      printInfo(`Platform: ${IS_MAC ? 'macOS' : 'Linux'}`);
   149→
   150→      // Step 1: chmod first - make files accessible
   151→      execSync(`chmod -R 755 "${targetDir}"`, { stdio: 'pipe' });
   152→      printSuccess('Step 1: chmod -R 755 (make accessible)');
   153→
   154→      // Step 2: chown - change ownership to current user
   155→      execSync(`chown -R ${info.uid}:${info.gid} "${targetDir}"`, { stdio: 'pipe' });
   156→      printSuccess(`Step 2: chown -R to ${info.username}`);
   157→
   158→      // Step 3: chmod again - set final permissions
   159→      execSync(`chmod -R 755 "${targetDir}"`, { stdio: 'pipe' });
   160→      printSuccess('Step 3: chmod -R 755 (final permissions)');
   161→    }
   162→
   163→    // Make scripts executable (cross-platform)
   164→    printInfo('Setting executable permissions...');
   165→    const execFiles = findExecutableFiles(targetDir);
   166→    for (const file of execFiles) {
   167→      makeExecutable(file);
   168→    }
   169→    printSuccess(`Set executable permissions on ${execFiles.length} files`);
   170→
   171→  } catch (err: any) {
   172→    printError(`Permission fix failed: ${err.message}`);
   173→    if (!IS_WINDOWS) {
   174→      print(`${c.yellow}Run: sudo chown -R $(whoami) ${targetDir}${c.reset}`);
   175→    }
   176→  }
   177→}
   178→
   179→// Cross-platform file search (replaces Unix find)
   180→function findExecutableFiles(dir: string, patterns: string[] = ['*.ts', '*.sh', '*.py']): string[] {
   181→  const results: string[] = [];
   182→
   183→  function walk(currentPath: string) {
   184→    try {
   185→      const files = readdirSync(currentPath);
   186→      for (const file of files) {
   187→        const fullPath = join(currentPath, file);
   188→        try {
   189→          const stat = require('fs').statSync(fullPath);
   190→
   191→          if (stat.isDirectory()) {
   192→            walk(fullPath);
   193→          } else {
   194→            // Check if file matches any pattern
   195→            for (const pattern of patterns) {
   196→              const regex = new RegExp(`^${pattern.replace('*', '.*')}$`);
   197→              if (regex.test(file)) {
   198→                results.push(fullPath);
   199→                break;
   200→              }
   201→            }
   202→          }
   203→        } catch (e) {
   204→          // Skip files we can't read
   205→        }
   206→      }
   207→    } catch (e) {
   208→      // Skip directories we can't read
   209→    }
   210→  }
   211→
   212→  walk(dir);
   213→  return results;
   214→}
   215→
   216→// Cross-platform executable permission
   217→function makeExecutable(filePath: string): void {
   218→  if (IS_WINDOWS) {
   219→    // Windows: Files are executable by extension (.exe, .bat, .ps1)
   220→    // For other files, no action needed (Git handles permissions)
   221→    return;
   222→  } else {
   223→    // Unix: chmod +x
   224→    try {
   225→      execSync(`chmod +x "${filePath}"`, { stdio: 'pipe' });
   226→    } catch (e) {
   227→      // Ignore errors
   228→    }
   229→  }
   230→}
