   349→// ============================================================================
   350→// CROSS-PLATFORM BUN INSTALLATION
   351→// ============================================================================
   352→
   353→function installBun(): void {
   354→  print('');
   355→  print(`${c.bold}Checking Bun Runtime${c.reset}`);
   356→  print(`${c.gray}─────────────────────────────────────────────────${c.reset}`);
   357→
   358→  try {
   359→    // Check if bun is installed
   360→    const bunVersion = execSync('bun --version', { encoding: 'utf-8', stdio: 'pipe' }).trim();
   361→    printSuccess(`Bun ${bunVersion} found`);
   362→
   363→    // Upgrade to latest
   364→    printInfo('Upgrading Bun to latest version...');
   365→    try {
   366→      execSync('bun upgrade', { stdio: 'inherit' });
   367→      const newVersion = execSync('bun --version', { encoding: 'utf-8' }).trim();
   368→      printSuccess(`Bun upgraded to ${newVersion}`);
   369→    } catch {
   370→      printWarning('Could not upgrade Bun (may already be latest)');
   371→    }
   372→  } catch {
   373→    // Bun not installed, install it
   374→    printInfo('Bun not found, installing...');
   375→    try {
   376→      if (IS_WINDOWS) {
   377→        // Windows: Use PowerShell installer
   378→        execSync('powershell -c "irm bun.sh/install.ps1 | iex"', {
   379→          stdio: 'inherit',
   380→          shell: 'powershell.exe'
   381→        });
   382→      } else {
   383→        // Unix: Use curl with bash
   384→        const result = execSync('curl -fsSL https://bun.sh/install', {
   385→          stdio: 'pipe',
   386→          encoding: 'utf-8'
   387→        });
   388→
   389→        const installScript = spawn('bash', ['-'], {
   390→          input: result,
   391→          stdio: 'inherit'
   392→        });
   393→
   394→        await new Promise<void>((resolve, reject) => {
   395→          installScript.on('close', (code) => {
   396→            if (code === 0) resolve();
   397→            else reject(new Error(`Bun install failed with code ${code}`));
   398→          });
   399→        });
   400→      }
   401→
   402→      // Add bun to PATH for current session
   403→      const bunPath = IS_WINDOWS
   404→        ? join(HOME, '.bun', 'bin')
   405→        : join(HOME, '.bun', 'bin');
   406→      process.env.PATH = `${bunPath}${IS_WINDOWS ? ';' : ':'}${process.env.PATH}`;
   407→
   408→      const newVersion = execSync('bun --version', { encoding: 'utf-8' }).trim();
   409→      printSuccess(`Bun ${newVersion} installed`);
   410→      printInfo('You may need to restart your terminal for bun to be in PATH');
   411→    } catch (err: any) {
   412→      printError(`Failed to install Bun: ${err.message}`);
   413→      if (IS_WINDOWS) {
   414→        printInfo('Please install manually: powershell -c "irm bun.sh/install.ps1 | iex"');
   415→      } else {
   416→        printInfo('Please install manually: curl -fsSL https://bun.sh/install | bash');
   417→      }
   418→    }
   419→  }
   420→}
