   425→
   426→function setupShellAlias(): void {
   427→  const aliasLine = IS_WINDOWS
   428→    ? `function pai { bun $env:USERPROFILE\.claude\skills\PAI\Tools\pai.ts $args }`
   429→    : `alias pai='bun ~/.claude/skills/PAI/Tools/pai.ts'`;
   430→
   431→  const marker = '# PAI alias';
   432→
   433→  try {
   434→    if (IS_WINDOWS) {
   435→      // PowerShell profile
   436→      const psProfilePath = join(HOME, 'Documents', 'PowerShell', 'Microsoft.PowerShell_profile.ps1');
   437→      let content = existsSync(psProfilePath) ? readFileSync(psProfilePath, 'utf-8') : '';
   438→
   439→      if (content.includes('function pai')) {
   440→        // Update existing
   441→        content = content.replace(/function pai \{[^}]*\}/s, aliasLine);
   442→        writeFileSync(psProfilePath, content);
   443→        printSuccess('Updated PAI alias in PowerShell profile');
   444→      } else {
   445→        // Add new
   446→        content = content.trim() + `\n${marker}\n${aliasLine}\n`;
   447→        writeFileSync(psProfilePath, content);
   448→        printSuccess('Added PAI alias to PowerShell profile');
   449→      }
   450→      printInfo('Restart PowerShell to use "pai" command');
   451→    } else {
   452→      // Unix shell: .zshrc or .bashrc
   453→      const zshrcPath = join(HOME, '.zshrc');
   454→      const bashrcPath = join(HOME, '.bashrc');
   455→
   456→      let targetFile = existsSync(zshrcPath) ? zshrcPath : bashrcPath;
   457→      if (!existsSync(targetFile)) {
   458→        // Create .zshrc as default
   459→        targetFile = zshrcPath;
   460→      }
   461→
   462→      let content = readFileSync(targetFile, 'utf-8');
   463→
   464→      if (content.includes('alias pai=')) {
   465→        // Update existing
   466→        content = content.replace(/alias pai=.*/, aliasLine);
   467→        writeFileSync(targetFile, content);
   468→        printSuccess(`Updated PAI alias in ${targetFile.split(sep).pop()}`);
   469→      } else {
   470→        // Add new
   471→        writeFileSync(targetFile, content + `\n${marker}\n${aliasLine}\n`);
   472→        printSuccess(`Added PAI alias to ${targetFile.split(sep).pop()}`);
   473→      }
   474→
   475→      const shellName = targetFile.includes('zsh') ? 'zsh' : 'bash';
   476→      printInfo(`Run "source ~/.${shellName}rc" to enable "pai" command`);
   477→    }
   478→  } catch (err: any) {
   479→    printWarning(`Could not update shell profile: ${err.message}`);
   480→  }
   481→}
