   483→function reloadShell(): void {
   484→  print('');
   485→  print(`${c.yellow}⚠️  Please restart your terminal/shell for changes to take effect.${c.reset}`);
   486→
   487→  if (IS_WINDOWS) {
   488→    print(`   ${c.gray}Close and reopen PowerShell or Command Prompt${c.reset}`);
   489→  } else if (IS_MAC) {
   490→    print(`   ${c.gray}Run: source ~/.zshrc${c.reset}`);
   491→  } else if (IS_LINUX) {
   492→    print(`   ${c.gray}Run: source ~/.bashrc or source ~/.zshrc${c.reset}`);
   493→  }
   494→}
