// ============================================================================

function setupShellAlias(): void {
  const aliasLine = IS_WINDOWS
    ? `function pai { bun $env:USERPROFILE\.claude\skills\PAI\Tools\pai.ts $args }`
    : `alias pai='bun ~/.claude/skills/PAI/Tools/pai.ts'`;

  const marker = '# PAI alias';

  try {
    if (IS_WINDOWS) {
      // PowerShell profile
      const psProfilePath = join(HOME, 'Documents', 'PowerShell', 'Microsoft.PowerShell_profile.ps1');
      let content = existsSync(psProfilePath) ? readFileSync(psProfilePath, 'utf-8') : '';

      if (content.includes('function pai')) {
        // Update existing
        content = content.replace(/function pai \{[^}]*\}/s, aliasLine);
        writeFileSync(psProfilePath, content);
        printSuccess('Updated PAI alias in PowerShell profile');
      } else {
        // Add new
        content = content.trim() + `\n${marker}\n${aliasLine}\n`;
        writeFileSync(psProfilePath, content);
        printSuccess('Added PAI alias to PowerShell profile');
      }
      printInfo('Restart PowerShell to use "pai" command');
    } else {
      // Unix shell: .zshrc or .bashrc
      const zshrcPath = join(HOME, '.zshrc');
      const bashrcPath = join(HOME, '.bashrc');

      let targetFile = existsSync(zshrcPath) ? zshrcPath : bashrcPath;
      if (!existsSync(targetFile)) {
        // Create .zshrc as default
        targetFile = zshrcPath;
      }

      let content = readFileSync(targetFile, 'utf-8');

      if (content.includes('alias pai=')) {
        // Update existing
        content = content.replace(/alias pai=.*/, aliasLine);
        writeFileSync(targetFile, content);
        printSuccess(`Updated PAI alias in ${targetFile.split(sep).pop()}`);
      } else {
        // Add new
        writeFileSync(targetFile, content + `\n${marker}\n${aliasLine}\n`);
        printSuccess(`Added PAI alias to ${targetFile.split(sep).pop()}`);
      }

      const shellName = targetFile.includes('zsh') ? 'zsh' : 'bash';
      printInfo(`Run "source ~/.${shellName}rc" to enable "pai" command`);
    }
  } catch (err: any) {
    printWarning(`Could not update shell profile: ${err.message}`);
  }
}

function reloadShell(): void {
  print('');
  print(`${c.yellow}⚠️  Please restart your terminal/shell for changes to take effect.${c.reset}`);

  if (IS_WINDOWS) {
    print(`   ${c.gray}Close and reopen PowerShell or Command Prompt${c.reset}`);
  } else if (IS_MAC) {
    print(`   ${c.gray}Run: source ~/.zshrc${c.reset}`);
  } else if (IS_LINUX) {
    print(`   ${c.gray}Run: source ~/.bashrc or source ~/.zshrc${c.reset}`);
  }
}

